ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?name WHERE {
  ?studio a :Studio .
  ?movies a :Movies .
  ?movies p:hasStudio ?studio .
  ?movies p:title ?title .
  ?studio p:name ?name .
} }
  full: { SELECT ?title ?name ?full_name WHERE {
  ?studio a :Studio .
  ?movies a :Movies .
  ?movies p:hasStudio ?studio .
  ?producer a :Producers .
  ?producer p:producer_id ?producer_id_l .
  ?movies p:studio_id ?studio_id_r .
  ?movies p:title ?title .
  ?studio p:name ?name .
  ?producer p:name ?full_name .
  FILTER(STR(?producer_id_l) = STR(?studio_id_r))
} }
  component_2: { SELECT ?title ?full_name WHERE {
  ?producer a :Producers .
  ?movies a :Movies .
  ?producer p:producer_id ?producer_id_l .
  ?movies p:studio_id ?studio_id_r .
  ?movies p:title ?title .
  ?producer p:name ?full_name .
  FILTER(STR(?producer_id_l) = STR(?studio_id_r))
} }
}

